#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

    qrad-((vRadius-.5)/3)*(.2+.05*audioMidSmooth);
    lfo1=vec3(1/3,-1/3,0)+1*.5+.5*sin(uTime*(9-audioMid-audioMidSmooth+(qrad*audioLowSmooth)+audioHigh));
    lfo2=vec3(1/3,-1/3,0)+1*.5+.5*cos(uTime*(9-audioMid-audioMidSmooth+audioLow+(qrad*audioHighSmooth)));

    // sample previous uFrame
    ret = texture( sampler_main, vUv ).xyx;

    // darken (decay) over uTime
    ret *= 0.895-.602*cos(qrad*lfo2.x); //or try: ret -= 0.004;
ret+=.2*(tex2d(sampler_pw_rand02,mix(vUv,vUvOriginal,(max(ret,1-ret)*.5+.3*lfo1.z))).xyz*.5+.5*lfo2)-.012*(ret-.02*sin(qrad*lfo1.x));

ret+=.2*(tex2d(sampler_fw_rand01,mix(vUv,vUvOriginal,(max(ret,1-ret)*.5+.3*lfo2.z))).xyz*.5+.5*lfo2)-.02*(ret-.02*cos(qrad*lfo2.z));


  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

  vec2 uv_flipped = vec2(1 - vUv.x,vUv.y);    // '1' auto-replicates to vec2(1,1)
            ret = max( texture(sampler_main, vUv).xyz,
                       texture(sampler_main, uv_flipped).xyz );
            ret = pow(ret, vec3(.88+0.5*(audioLow-audioLowSmooth*audioHighSmooth)*sin(uTime*0.15), 1.12+0.5*(audioLow-audioLowSmooth*audioMidSmooth)*sin(uTime*0.13),1+0.5*(audioLow-audioLowSmooth*audioHighSmooth)*sin(uTime*0.12)));

  fragColor = ret;
}
